/*! igdc-pay.engine.js
 * IGDC Unified Payment & Monetization Engine
 * Purpose:
 *  - Single entry for ALL payment / donation / affiliate / media monetization
 *  - Safe without PG
 *  - Works across all front pages
 *  - Server-side keys only (via Netlify Functions)
 */

(function (w, d) {
  "use strict";

  if (w.IGDC && w.IGDC.__ENGINE_READY__) return;
  w.IGDC = w.IGDC || {};
  w.IGDC.__ENGINE_READY__ = true;

  const CFG = w.IGDC.PAYCFG || {};

  const ENDPOINTS = {
    checkout: CFG.checkout || "/.netlify/functions/checkout",
    status: CFG.status || "/.netlify/functions/status"
  };

  /* --------------------------------------------------
   Utils
  -------------------------------------------------- */
  const $ = (q, r) => (r || d).querySelector(q);
  const $$ = (q, r) => Array.from((r || d).querySelectorAll(q));

  const now = () => Date.now();
  const safe = v => (v === undefined || v === null ? "" : v);
  const num = v => isNaN(parseFloat(v)) ? 0 : parseFloat(v);

  function fetchJSON(url, opt) {
    return fetch(url, opt).then(r => {
      if (!r.ok) throw r;
      return r.json().catch(() => ({}));
    });
  }

  /* --------------------------------------------------
   Modal
  -------------------------------------------------- */
  function modal(title, html) {
    let box = d.getElementById("igdc-modal");
    if (!box) {
      box = d.createElement("div");
      box.id = "igdc-modal";
      box.style.cssText =
        "position:fixed;inset:0;z-index:999999;background:rgba(0,0,0,.55);display:none;";
      box.innerHTML = `
        <div style="max-width:520px;margin:10vh auto;background:#fff;border-radius:14px;overflow:hidden">
          <div style="padding:12px 16px;font-weight:800;border-bottom:1px solid #eee;display:flex;justify-content:space-between">
            <span id="igdc-modal-title"></span>
            <button id="igdc-modal-close">×</button>
          </div>
          <div id="igdc-modal-body" style="padding:16px"></div>
        </div>`;
      d.body.appendChild(box);
      $("#igdc-modal-close", box).onclick = () => (box.style.display = "none");
    }
    $("#igdc-modal-title", box).textContent = title || "안내";
    $("#igdc-modal-body", box).innerHTML = html || "";
    box.style.display = "block";
  }

  /* --------------------------------------------------
   Status
  -------------------------------------------------- */
  let STATUS_CACHE = { t: 0, v: null };

  function getStatus() {
    if (STATUS_CACHE.v && now() - STATUS_CACHE.t < 120000)
      return Promise.resolve(STATUS_CACHE.v);

    return fetchJSON(ENDPOINTS.status)
      .catch(() => fetchJSON("/.netlify/functions/status"))
      .catch(() => ({ payment: {} }))
      .then(v => {
        STATUS_CACHE = { t: now(), v };
        return v;
      });
  }

  /* --------------------------------------------------
   Core Pay Router
  -------------------------------------------------- */
  function routePay(opt) {
    opt = opt || {};
    const mode = opt.mode || "auto";
    const amount = num(opt.amount);
    const url = safe(opt.url);
    const title = safe(opt.title);
    const method = (opt.method || "card").toLowerCase();
    const source = opt.source || location.pathname;

    // 1. Affiliate / external redirect
    if (mode === "affiliate" || mode === "external") {
      if (url) location.href = url;
      return;
    }

    // 2. Tracking only
    if (mode === "tracking") {
      if (w.dataLayer) w.dataLayer.push({ event: "igdc_track", title, source });
      if (url) location.href = url;
      return;
    }

    // 3. Internal / Donation / Auto
    return getStatus().then(status => {
      const enabled = status?.payment?.[method];

      if (!enabled) {
        modal(
          "결제 준비중",
          `<div style="font-size:14px;line-height:1.6">
            현재 결제 시스템이 준비 중입니다.<br/>
            추후 자동으로 활성화됩니다.
          </div>`
        );
        return;
      }

      const payload = {
        method,
        amount,
        title,
        source,
        meta: opt.meta || {},
        purpose: opt.purpose || "commerce"
      };

      return fetchJSON(ENDPOINTS.checkout, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload)
      })
        .then(res => {
          if (res.redirectUrl) {
            location.href = res.redirectUrl;
            return;
          }
          if (res.html) {
            modal("결제", res.html);
            return;
          }
          modal("결제", "결제 요청이 접수되었습니다.");
        })
        .catch(() => {
          modal("오류", "결제 서버에 연결할 수 없습니다.");
        });
    });
  }

  /* --------------------------------------------------
   Auto bind DOM
  -------------------------------------------------- */
  function bind(el) {
    if (!el || el.__igdcBound) return;
    el.__igdcBound = true;

    el.addEventListener("click", e => {
      const href = el.getAttribute("href") || "";
      const opt = {
        mode: el.dataset.mode || "auto",
        method: el.dataset.method,
        amount: el.dataset.amount,
        title: el.dataset.title || el.textContent.trim(),
        url: href,
        purpose: el.dataset.purpose || "commerce"
      };

      if (opt.mode !== "external") e.preventDefault();
      routePay(opt);
    });
  }

  function scan() {
    $$("[data-pay],[data-method],[data-amount],[data-mode]").forEach(bind);
  }

  if ("MutationObserver" in w) {
    new MutationObserver(scan).observe(d.documentElement, {
      childList: true,
      subtree: true
    });
  }

  d.addEventListener("DOMContentLoaded", scan);

  /* --------------------------------------------------
   Public API
  -------------------------------------------------- */
  w.IGDC.pay = routePay;
  w.IGDC.openPayment = routePay;

  // event bridge
  d.addEventListener("psom:payment", e => routePay(e.detail || {}));
  w.addEventListener("message", e => {
    if (e?.data?.type === "IGDC_PAY") routePay(e.data.payload || {});
  });

})(window, document);
